const payload = $input.first().json.body;
if (payload?.event !== 'messages.upsert') {
  return [{ json: { skip: true, motivo: `Evento ignorado: ${payload?.event}` } }];
}
const data = payload?.data;
const key = data?.key;
if (key?.fromMe === true) {
  return [{ json: { skip: true, motivo: 'Mensaje propio (fromMe)' } }];
}
const remoteJid = key?.remoteJid || '';
if (remoteJid.endsWith('@g.us')) {
  return [{ json: { skip: true, motivo: 'Mensaje de grupo' } }];
}
const telefono = remoteJid.split('@')[0];
const messageType = data?.messageType;
const message = data?.message;
let texto = null;
let esAudio = false;
if (messageType === 'conversation') {
  texto = message?.conversation ?? null;
} else if (messageType === 'extendedTextMessage') {
  texto = message?.extendedTextMessage?.text ?? null;
} else if (messageType === 'audioMessage') {
  esAudio = true;
}
return [{
  json: {
    telefono,
    remoteJid,
    tipo: messageType,
    texto,
    esAudio,
    contacto: data?.pushName || telefono,
    messageId: key?.id,
    instanceName: payload?.instance,
    skip: !texto && !esAudio
  }
}];

const response = $input.first().json;
const base64Data = response.base64;
const mimeType = response.mimetype || 'audio/ogg; codecs=opus';
const datosOriginales = $('Extraer Datos Mensaje').first().json;

return [{
  json: {
    telefono: datosOriginales.telefono,
    remoteJid: datosOriginales.remoteJid,
    contacto: datosOriginales.contacto,
    messageId: datosOriginales.messageId,
  },
  binary: {
    data: {
      data: base64Data,
      mimeType: mimeType,
      fileName: 'audio.ogg',
    }
  }
}];

const transcripcion = $input.first().json;
const texto = transcripcion.text || '';
const datosOriginales = $('Extraer Datos Mensaje').first().json;

return [{
  json: {
    telefono: datosOriginales.telefono,
    remoteJid: datosOriginales.remoteJid,
    tipo: 'audioMessage',
    texto: texto,
    esAudio: true,
    contacto: datosOriginales.contacto,
    messageId: datosOriginales.messageId,
    instanceName: datosOriginales.instanceName,
    skip: false
  }
}];

const respuesta = $input.first().json;
const datosOriginales = $('Extraer Datos Mensaje').first().json;

return [{
  json: {
    telefono: datosOriginales.telefono,
    remoteJid: datosOriginales.remoteJid,
    contacto: datosOriginales.contacto,
    messageId: datosOriginales.messageId,
    instanceName: datosOriginales.instanceName,
    texto: respuesta.data.textoCombinado,
    mensajesAcumulados: respuesta.data.cantidadMensajes,
    skip: false
  }
}];
